//-------------------------------------------------------------------------
// 조건변경 팝업
//-------------------------------------------------------------------------
scwin.f_wrkInIndictAddCreat = async function () {
  if (ds_master.getRowCount() == 0 || ds_master.getRowPosition() < 0) return;
  let flag = "";
  for (var row = 0; row < ds_master.getRowCount(); row++) {
    if (ds_master.getCellData(row, "modCls") == "T") {
      flag = "T";
    }
  }
  if ($c.gus.cfIsNull($p, flag)) {
    $c.win.alert($p, "선택된 작업이 없습니다.");
    return;
  }
  /*
      var paramArray = new Object();
      //paramArray["wrkIndictNo"] = wrkIndictNo;  
      paramArray["ica_wrkDt"] = ds_master.NameString(ds_master.RowPosition,"wrkDt");
      paramArray["lc_wrkShift"] = ds_master.NameString(ds_master.RowPosition,"wrkShift");
      
      var returnValue = window.showModalDialog('/to/in/bulk/tmlbulk/in_201_02_14p.jsp'
                                              ,paramArray
                                              ,"dialogWidth:330px; dialogHeight:250px; status:No");
  
  */
  let wrkDt = ds_master.getCellData(ds_master.getRowPosition(), "wrkDt");
  let wrkShift = ds_master.getCellData(ds_master.getRowPosition(), "wrkDt");
  let win_url = "/ui/to/in/bulk/tmlbulk/in_201_02_14p.xml";
  let opts = scwin.opts || {};
  opts.modal = true;
  opts.type = "browserPopup";
  opts.id = scwin.popupID || "pupup";
  opts.width = 355;
  opts.height = 255;
  opts.popupName = '벌크작업지시작업단위변경등록';
  let param = {
    ica_wrkDt: wrkDt,
    lc_wrkShift: wrkShift
  };
  rtnList = await $c.win.openPopup($p, win_url, opts, param);
  if ($c.gus.cfIsNull($p, rtnList)) return;
  let endRow = ds_master.getRowCount();
  let sysMappingKeyArray = [];
  for (let row = 0; row < endRow; row++) {
    if (ds_master.getCellData(row, "modCls") == "T") {
      ds_master.insertRow();
      let mascnt = ds_master.getRowCount();

      // targetRow = $c.gus.f_CopyDataRow(ds_master, ds_master, row);
      ds_master.setRowJSON(mascnt - 1, ds_master.getRowJSON(row), true);
      var beforeRow = row;
      ds_master.setCellData(row, "modCls", "F");
      let sysMappingKey = scwin.f_MakeIndex();
      ds_master.setCellData(mascnt - 1, "modCls", "T"); //ds_master.getRowPosition() -> row(바로아래)
      ds_master.setCellData(mascnt - 1, "sysMappingKey", ds_master.getCellData(row, "sysMappingKey") + "_"); // "" 대신에 "_"가 있었음.  
      ds_master.setCellData(mascnt - 1, "wrkDt", rtnList.wrkDt);
      ds_master.setCellData(mascnt - 1, "wrkShift", rtnList.wrkShift);
      ds_master.setCellData(mascnt - 1, "wrkDtShift", rtnList.wrkDt + rtnList.wrkShift);
      ds_master.setCellData(mascnt - 1, "wrkIndictNo", "");
      //ds_master.NameString(ds_master.getRowPosition(),"wrkPlanIndictRelCd", "<%=TOConstants.WRK_PLAN_INDICT_REL_DIVISION%>";
      //ds_master.setCellData(ds_master.getRowPosition(),"wrkIndictPrgsStsCd", "<%=TOConstants.WRK_INDICT_PRGS_STS_INDICT%>");
      ds_master.setCellData(mascnt - 1, "wrkIndictPrgsStsCd", "01");
      ds_master.setCellData(mascnt - 1, "wrkPlanIndictRelSeq", 0);
      if (ds_master.getRowStatus(beforeRow) == "C") {
        ds_master.removeRow(beforeRow);
      }
      ds_master.setRowPosition(row);
      /*
      ds_detail.UseFilter=1;
      ds_detail.Filter(); 
      */
      scwin.dsDetailFilter();
      if (!$c.gus.isInArray($p, sysMappingKeyArray, ds_master.getCellData(row, "sysMappingKey"))) {
        sysMappingKeyArray[sysMappingKeyArray.length] = ds_master.getCellData(row, "sysMappingKey");
        $c.win.alert($p, "동일한 차량이 생성됩니다.");
        scwin.f_wrkInIndictAddCreatDetail(row, mascnt); //targetRow->mascnt
      }

      //ds_master.Undo(row); //상태값 되돌림?
      //$c.data.undoRow(ds_master); //초기조회상태로 돌려 막음
    }
  }
  ds_master.setRowPosition(ds_master.getRowCount() - 1);
  gr_master.setFocusedCell(ds_master.getRowCount() - 1, "wrkDt");
};

