//-------------------------------------------------------------------------
// 셔틀 저장
//-------------------------------------------------------------------------
scwin.f_saveShtlMaster = async function () {
  var flag = "";
  var preWrkPatternCd = "";
  var i = 0;
  for (row = 0; row < ds_master.getRowCount(); row++) {
    if (ds_master.getCellData(row, "modCls") == "T") {
      if (ds_master.getCellData(row, "wrkPatternCd") == "05" || ds_master.getCellData(row, "wrkPatternCd") == "06" || ds_master.getCellData(row, "wrkPatternCd") == "07" || ds_master.getCellData(row, "wrkPatternCd") == "08" || ds_master.getCellData(row, "wrkPatternCd") == "12" || ds_master.getCellData(row, "wrkPatternCd") == "13") {
        if (i == 0) preWrkPatternCd = ds_master.getCellData(row, "wrkPatternCd");
        if (preWrkPatternCd == ds_master.getCellData(row, "wrkPatternCd")) {
          preWrkPatternCd = ds_master.getCellData(row, "wrkPatternCd");
        } else {
          $c.win.alert($p, "작업유형이 동일해야 합니다.");
          return;
        }
        i++;
      } else {
        $c.win.alert($p, "셔틀이 아닌 작업유형이 있습니다.");
        return;
      }
      flag = "T";
    }
  }
  if ($c.gus.cfIsNull($p, flag)) {
    $c.win.alert($p, "선택된 작업이 없습니다.");
    return;
  }
  var chkMst = await $c.gus.cfValidate($p, [gr_master]);
  var chkDtl = await $c.gus.cfValidate($p, [gr_detail]);
  if (!chkMst) return;
  if (!chkDtl) return;
  var chkAlert = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (chkAlert) {
    scwin.bInTrPost = true;
    //ds_detail.UseChangeInfo = "false";
    //tr_shtlMaster.post();
    $c.sbm.execute($p, sbm_shtlMaster);
  }
};

//-------------------------------------------------------------------------
// 벌크작업지시차량내역 행 추가
//-------------------------------------------------------------------------
scwin.f_addDetail = async function () {
  if (ds_master.getRowCount() == 0) {
    $c.win.alert($p, "지시내역이 없습니다.");
    return;
  }
  ;

  //if(ds_master.RowStatus(ds_master.RowPosition) == 1) {
  //  cfAlertMsg("벌크작업지시내역이 추가되었습니다.\n벌크작업지시내역을 저장 후 계속하십시요.");
  //  return;
  //}

  var c = 0;
  if (ds_detail.getRowCount() > 0) {
    for (var i = 0; i < ds_detail.getRowCount(); i++) {
      var rowStatus = ds_detail.getRowStatus(i);
      if (rowStatus != "R") {
        c = 1;
        break;
      }
    }
  }
  if (c != 1) {
    //tr_chkCondition.post();
    await $c.sbm.execute($p, sbm_chkCondition);
  } else {
    scwin.dsDetailFilter();
    var oldRow = ds_detail.getRowPosition();
    ds_detail.insertRow();
    ds_detail.setRowPosition(ds_detail.getRowCount() - 1);
    //gr_detail.setFocusedCell(ds_detail.getRowCount()-1,0);

    await scwin.chkCanAddRowindexchangeDtl(oldRow);
    ds_master.setCellData(ds_master.getRowPosition(), "modCls", "T");
    ds_detail.setCellData(ds_detail.getRowPosition(), "sysMappingKey", ds_master.getCellData(ds_master.getRowPosition(), 'sysMappingKey'));
    ds_detail.setCellData(ds_detail.getRowPosition(), "wrkIndictNo", ds_master.getCellData(ds_master.getRowPosition(), "wrkIndictNo"));
    //ds_detail.NameString(ds_detail.getRowPosition(),"wrkIndictPrgsStsCd") = "<%=TOConstants.WRK_INDICT_PRGS_STS_INDICT%>";
    ds_detail.setCellData(ds_detail.getRowPosition(), "wrkIndictPrgsStsCd", "01");
    ds_detail.setCellData(ds_detail.getRowPosition(), "wrkVehclWaitPosCd", "01");
    ds_detail.setCellData(ds_detail.getRowPosition(), "vehclIndictQty", ds_master.getCellData(ds_master.getRowPosition(), "indictQty"));
    ds_detail.setCellData(ds_detail.getRowPosition(), "vehclIndictWt", ds_master.getCellData(ds_master.getRowPosition(), "indictWt"));
    ds_detail.setCellData(ds_detail.getRowPosition(), "vehclIndictCbm", ds_master.getCellData(ds_master.getRowPosition(), "indictCbm"));

    //cfShowTotalRows(totalRows2,ds_detail.CountRow);

    spa_cnt2.setValue(ds_detail.getRowCount());
  }
};

//-------------------------------------------------------------------------
// 벌크작업지시차량내역 행 삭제
//-------------------------------------------------------------------------
scwin.f_deleteDetail = function () {
  if (ds_detail.getRowCount() == 0) {
    $c.win.alert($p, "차량내역이 없습니다.");
    return;
  }

  //ds_detail.deleteRow(ds_detail.getRowPosition());
  if (ds_detail.getRowStatus(ds_detail.getRowPosition()) == "C") {
    ds_detail.removeRow(ds_detail.getRowPosition());
  } else {
    var row = ds_detail.getRowPosition();
    ds_detail.deleteRow(ds_detail.getRowPosition());
    ds_detail.setRowPosition(row);
  }

  //cfShowTotalRows(totalRows2,ds_detail.CountRow);
  spa_cnt2.setValue(ds_detail.getRowCount());
};

//-------------------------------------------------------------------------
