scwin.chkCanRowindexchangeMst = async function (oldRow) {
  if (oldRow > -1) {
    if (ds_master.getCellData(oldRow, "wrkDt") == "") {
      $c.win.alert($p, "필수입력 에러:작업일자");
      gr_master.setFocusedCell(oldRow, "wrkDt");
      return false;
    }
    if (ds_master.getCellData(oldRow, "wrkShift") == "") {
      $c.win.alert($p, "필수입력 에러:작업시프트");
      gr_master.setFocusedCell(oldRow, "wrkShift");
      return false;
    }
    if (ds_master.getCellData(oldRow, "wrkPlanIndictRelCd") == "") {
      $c.win.alert($p, "필수입력 에러:작업계획지시관계");
      gr_master.setFocusedCell(oldRow, "wrkPlanIndictRelCd");
      return false;
    }
    if (ds_master.getCellData(oldRow, "clntNm") == "") {
      $c.win.alert($p, "필수입력 에러:화주");
      gr_master.setFocusedCell(oldRow, "clntNm");
      return false;
    }
    if (ds_master.getCellData(oldRow, "commNm") == "") {
      $c.win.alert($p, "필수입력 에러:품명");
      gr_master.setFocusedCell(oldRow, "commNm");
      return false;
    }
    if (ds_master.getCellData(oldRow, "wrkPlNm") == "") {
      $c.win.alert($p, "필수입력 에러:작업장");
      gr_master.setFocusedCell(oldRow, "wrkPlNm");
      return false;
    }
    if (ds_master.getCellData(oldRow, "strRateAdptDt") == "") {
      $c.win.alert($p, "필수입력 에러:보관료적용일자");
      gr_master.setFocusedCell(oldRow, "strRateAdptDt");
      return false;
    }
    if (ds_master.getCellData(oldRow, "wrkPatternCd") == "") {
      $c.win.alert($p, "필수입력 에러:작업유형");
      gr_master.setFocusedCell(oldRow, "wrkPatternCd");
      return false;
    }
    if (ds_master.getCellData(oldRow, "gaugePatternCd") == "") {
      $c.win.alert($p, "필수입력 에러:측정유형");
      gr_master.setFocusedCell(oldRow, "gaugePatternCd");
      return false;
    }
    for (i = 0; i < ds_detail.getRowCount(); i++) {
      if (ds_detail.getCellData(i, "vehclNo") == "") {
        $c.win.alert($p, "필수입력 에러:차량번호");
        return false;
      }
      if (ds_detail.getCellData(i, "wrkVehclWaitPosCd") == "") {
        $c.win.alert($p, "필수입력 에러:차량대기위치");
        return false;
      }
      if (ds_detail.getCellData(i, "wrkIndictPrgsStsCd") == "") {
        $c.win.alert($p, "필수입력 에러:작업진행상태");
        return false;
      }
    }
  }
  return true;
};
