scwin.sbm_condition_submitdone = function (e) {
  var rowCnt = ds_master.getRowCount();
  if ($c.gus.cfCheckCreateFlag($p) == true) {
    $c.gus.cfTurnCreateFlag($p, false);
  } else {
    if (rowCnt == 0) {
      $c.win.alert($p, MSG_CM_WRN_002);
    } else {
      scwin.f_retrieveDetail(ds_master.getCellData(0, "wrkIndictNo"));
    }
  }
  if (rowCnt != 0) {
    gr_master.setFocusedCell(0, 0);
    scwin.dsDetailFilter();
  }

  //cfShowTotalRows(totalRows,rowCnt);
  spa_cnt1.setValue(rowCnt);
};

